# Pseudo-code for initializing a CAM in a DVB-CI system
class ConditionalAccessModule:
    def __init__(self, module_type):
        self.module_type = module_type
        self.keys = None

    def load_subscriber_card(self, card_data):
        # Simulate loading access keys from the subscriber card
        self.keys = card_data.get('access_keys')
        return self.keys is not None

# Example usage
cam = ConditionalAccessModule(module_type='DVB-CI')
subscriber_card = {'access_keys': ['key1', 'key2']}
if cam.load_subscriber_card(subscriber_card):
    print("CAM initialized with access keys.")
